#[cfg(test)]
mod tests {
    use super::{AUDITED_LANGUAGE_SPEC_COUNT, LANGUAGE_SPECS, language_spec};

    #[test]
    fn registry_is_complete_sorted_and_matches_callable_pack() {
        assert_eq!(AUDITED_LANGUAGE_SPEC_COUNT, 159);
        assert!(
            LANGUAGE_SPECS
                .windows(2)
                .all(|pair| pair[0].id < pair[1].id)
        );
        assert!(language_spec("nim").is_none());
        assert!(language_spec("rust").is_some());
        assert!(language_spec("mojo").is_some());
    }
}
